import React, { useState, useEffect } from 'react';
import { salesAPI, productsAPI } from '../services/api';

function Sales() {
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [processing, setProcessing] = useState(false);
  const [recentSales, setRecentSales] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [productsRes, salesRes] = await Promise.all([
        productsAPI.getAll().catch(() => ({ data: [] })),
        salesAPI.getAll().catch(() => ({ data: [] })),
      ]);
      setProducts(productsRes.data);
      setRecentSales(salesRes.data.slice(0, 10));
      setError(null);
    } catch (err) {
      setError('Failed to load data');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const addToCart = (product) => {
    const existingItem = cart.find((item) => item.product === product.id);
    if (existingItem) {
      setCart(
        cart.map((item) =>
          item.product === product.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        )
      );
    } else {
      setCart([
        ...cart,
        {
          product: product.id,
          name: product.name,
          price: parseFloat(product.price),
          quantity: 1,
        },
      ]);
    }
  };

  const removeFromCart = (productId) => {
    setCart(cart.filter((item) => item.product !== productId));
  };

  const updateQuantity = (productId, quantity) => {
    if (quantity <= 0) {
      removeFromCart(productId);
    } else {
      setCart(
        cart.map((item) =>
          item.product === productId ? { ...item, quantity } : item
        )
      );
    }
  };

  const clearCart = () => {
    setCart([]);
  };

  const calculateTotal = () => {
    return cart.reduce((total, item) => total + item.price * item.quantity, 0);
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount);
  };

  const handleCheckout = async () => {
    if (cart.length === 0) {
      setError('Cart is empty');
      return;
    }

    setProcessing(true);
    try {
      const saleData = {
        items: cart.map((item) => ({
          product: item.product,
          quantity: item.quantity,
          unit_price: item.price,
        })),
        total_amount: calculateTotal(),
      };

      await salesAPI.create(saleData);
      clearCart();
      fetchData();
      alert('Sale completed successfully!');
    } catch (err) {
      setError('Failed to process sale');
      console.error(err);
    } finally {
      setProcessing(false);
    }
  };

  const filteredProducts = products.filter((product) =>
    product.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return <div className="loading">Loading POS...</div>;
  }

  return (
    <div>
      <div className="page-header">
        <h1>Point of Sale</h1>
      </div>

      {error && <div className="error">{error}</div>}

      <div className="pos-container">
        <div className="card">
          <h3>Products</h3>
          <div className="form-group">
            <input
              type="text"
              placeholder="Search products..."
              className="search-input"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="products-grid">
            {filteredProducts.map((product) => (
              <div
                key={product.id}
                className="product-card"
                onClick={() => addToCart(product)}
              >
                <h4>{product.name}</h4>
                <p className="price">{formatCurrency(product.price)}</p>
                <p style={{ fontSize: '0.8rem', color: '#7f8c8d' }}>
                  Stock: {product.stock_quantity}
                </p>
              </div>
            ))}
          </div>
          {filteredProducts.length === 0 && (
            <p className="empty-state">No products found</p>
          )}
        </div>

        <div className="card">
          <h3>Cart</h3>
          {cart.length === 0 ? (
            <p className="empty-state">Cart is empty</p>
          ) : (
            <>
              <div className="cart-items">
                {cart.map((item) => (
                  <div key={item.product} className="cart-item">
                    <div className="cart-item-info">
                      <h4>{item.name}</h4>
                      <p style={{ color: '#7f8c8d' }}>
                        {formatCurrency(item.price)} each
                      </p>
                    </div>
                    <div className="cart-item-controls">
                      <button
                        onClick={() =>
                          updateQuantity(item.product, item.quantity - 1)
                        }
                      >
                        -
                      </button>
                      <span>{item.quantity}</span>
                      <button
                        onClick={() =>
                          updateQuantity(item.product, item.quantity + 1)
                        }
                      >
                        +
                      </button>
                      <button
                        className="btn-danger"
                        onClick={() => removeFromCart(item.product)}
                        style={{ marginLeft: '10px' }}
                      >
                        ×
                      </button>
                    </div>
                  </div>
                ))}
              </div>
              <div className="cart-summary">
                <div className="cart-total">
                  <span>Total:</span>
                  <span>{formatCurrency(calculateTotal())}</span>
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button
                    className="btn btn-danger"
                    onClick={clearCart}
                    style={{ flex: 1 }}
                  >
                    Clear
                  </button>
                  <button
                    className="btn btn-success"
                    onClick={handleCheckout}
                    disabled={processing}
                    style={{ flex: 1 }}
                  >
                    {processing ? 'Processing...' : 'Checkout'}
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      <div className="card" style={{ marginTop: '20px' }}>
        <h3>Recent Sales</h3>
        {recentSales.length === 0 ? (
          <p className="empty-state">No sales yet</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Date</th>
                <th>Items</th>
                <th>Total</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {recentSales.map((sale) => (
                <tr key={sale.id}>
                  <td>#{sale.id}</td>
                  <td>
                    {new Date(sale.created_at).toLocaleDateString('en-US', {
                      month: 'short',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit',
                    })}
                  </td>
                  <td>{sale.items?.length || 0}</td>
                  <td>{formatCurrency(sale.total_amount)}</td>
                  <td>
                    <span
                      style={{
                        padding: '4px 8px',
                        borderRadius: '4px',
                        backgroundColor:
                          sale.status === 'completed'
                            ? '#d4edda'
                            : sale.status === 'cancelled'
                            ? '#f8d7da'
                            : '#fff3cd',
                        color:
                          sale.status === 'completed'
                            ? '#155724'
                            : sale.status === 'cancelled'
                            ? '#721c24'
                            : '#856404',
                      }}
                    >
                      {sale.status || 'completed'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

export default Sales;
